// Helper: get city data by slug
export function getCityBySlug(slug) {
  return cities.find(c => c.slug === slug) || null;
}

// Helper: get static paths for Astro
export function getCityPaths() {
  return cities.map(c => ({ params: { city: c.slug } }));
}
